import{_ as a,o as l,c as i,a3 as o}from"./chunks/framework.CqLY61E_.js";const m=JSON.parse('{"title":"Lab 08 — DDL de maintenance","description":"","frontmatter":{"title":"Lab 08 — DDL de maintenance","aside":true},"headers":[],"relativePath":"labs/lab08-ddl-maintenance.md","filePath":"labs/lab08-ddl-maintenance.md"}'),t={name:"labs/lab08-ddl-maintenance.md"};function r(n,e,d,c,u,s){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="lab-08-—-ddl-de-maintenance" tabindex="-1">Lab 08 — DDL de maintenance <a class="header-anchor" href="#lab-08-—-ddl-de-maintenance" aria-label="Permalink to &quot;Lab 08 — DDL de maintenance&quot;">​</a></h1><h2 id="objectif-du-laboratoire" tabindex="-1">Objectif du laboratoire <a class="header-anchor" href="#objectif-du-laboratoire" aria-label="Permalink to &quot;Objectif du laboratoire&quot;">​</a></h2><p>Mettre en pratique les opérations de maintenance de schéma sur des tables déjà existantes de <strong>Chinook</strong> à l&#39;aide de <code>alter table</code>.</p><div class="bg-red-50 border border-red-300 text-red-900 rounded-lg p-4 mb-5"><strong>Important</strong><br> Conservez une copie de toutes vos instructions. Au besoin, supprimez et restaurez la base de données car ce laboratoire modifie directement les vraies tables de Chinook. </div><hr><h2 id="mise-en-place" tabindex="-1">Mise en place <a class="header-anchor" href="#mise-en-place" aria-label="Permalink to &quot;Mise en place&quot;">​</a></h2><p>Dans ce laboratoire, vous travaillez directement sur les tables existantes :</p><ul><li><code>employe</code></li><li><code>piste</code></li><li><code>client</code></li><li><code>facture</code></li><li><code>ligne_facture</code></li></ul><h3 id="ordre-de-travail-recommande" tabindex="-1">Ordre de travail recommandé <a class="header-anchor" href="#ordre-de-travail-recommande" aria-label="Permalink to &quot;Ordre de travail recommandé&quot;">​</a></h3><p>Pour chaque modification :</p><ol><li>observez d&#39;abord la structure actuelle</li><li>appliquez une seule modification à la fois</li><li>vérifiez le résultat dans DBeaver</li><li>testez lorsque c&#39;est pertinent</li></ol><hr><h2 id="alter-table" tabindex="-1">Alter table <a class="header-anchor" href="#alter-table" aria-label="Permalink to &quot;Alter table&quot;">​</a></h2><h3 id="_1-ajouter-une-colonne-date-fin-emploi" tabindex="-1">1. Ajouter une colonne <code>date_fin_emploi</code> <a class="header-anchor" href="#_1-ajouter-une-colonne-date-fin-emploi" aria-label="Permalink to &quot;1. Ajouter une colonne `date_fin_emploi`&quot;">​</a></h3><p>Ajoutez à la table <code>employe</code> :</p><ul><li><code>date_fin_emploi</code> de type <code>date</code></li></ul><p>Vérifiez ensuite que :</p><ul><li>la colonne existe</li><li>les lignes actuelles contiennent <code>null</code></li></ul><h3 id="_2-ajouter-une-colonne-actif-avec-valeur-par-defaut" tabindex="-1">2. Ajouter une colonne <code>actif</code> avec valeur par défaut <a class="header-anchor" href="#_2-ajouter-une-colonne-actif-avec-valeur-par-defaut" aria-label="Permalink to &quot;2. Ajouter une colonne `actif` avec valeur par défaut&quot;">​</a></h3><p>Ajoutez à la table <code>employe</code> :</p><ul><li><code>actif</code></li><li>type <code>boolean</code></li><li><code>not null</code></li><li>valeur par défaut <code>true</code></li></ul><p>Vérifiez que les lignes déjà présentes reçoivent bien une valeur.</p><h3 id="_3-ajouter-une-contrainte-unique-sur-courriel" tabindex="-1">3. Ajouter une contrainte <code>unique</code> sur <code>courriel</code> <a class="header-anchor" href="#_3-ajouter-une-contrainte-unique-sur-courriel" aria-label="Permalink to &quot;3. Ajouter une contrainte `unique` sur `courriel`&quot;">​</a></h3><p>Ajoutez sur la table <code>employe</code> une contrainte <code>unique</code> sur :</p><ul><li><code>courriel</code></li></ul><p>Avant d&#39;ajouter la contrainte, vérifiez d&#39;abord si des doublons existent déjà à l&#39;aide d&#39;une requête <code>select</code>.</p><h3 id="_4-renommer-telephone" tabindex="-1">4. Renommer <code>telephone</code> <a class="header-anchor" href="#_4-renommer-telephone" aria-label="Permalink to &quot;4. Renommer `telephone`&quot;">​</a></h3><p>Renommez dans la table <code>employe</code> :</p><ul><li><code>telephone</code> en <code>telephone_principal</code></li></ul><p>Vérifiez que :</p><ul><li>la colonne a bien changé de nom</li><li>les données ont été conservées</li></ul><h3 id="_5-supprimer-la-colonne-fax" tabindex="-1">5. Supprimer la colonne <code>fax</code> <a class="header-anchor" href="#_5-supprimer-la-colonne-fax" aria-label="Permalink to &quot;5. Supprimer la colonne `fax`&quot;">​</a></h3><p>Supprimez dans la table <code>employe</code> :</p><ul><li><code>fax</code></li></ul><p>Rappel :</p><ul><li>ce type de suppression est moins fréquent</li><li>avant de supprimer en contexte réel, il faut vérifier si d&#39;autres systèmes utilisent déjà cette donnée</li></ul><h3 id="_6-rendre-album-id-et-genre-id-obligatoires-dans-piste" tabindex="-1">6. Rendre <code>album_id</code> et <code>genre_id</code> obligatoires dans <code>piste</code> <a class="header-anchor" href="#_6-rendre-album-id-et-genre-id-obligatoires-dans-piste" aria-label="Permalink to &quot;6. Rendre `album_id` et `genre_id` obligatoires dans `piste`&quot;">​</a></h3><p>Modifiez la table <code>piste</code> pour rendre <code>not null</code> :</p><ul><li><code>album_id</code></li><li><code>genre_id</code></li></ul><p>Avant d&#39;appliquer ce changement, vérifiez s&#39;il existe déjà des lignes où :</p><ul><li><code>album_id is null</code></li><li><code>genre_id is null</code></li></ul><p>Si c&#39;est le cas, il faut corriger ces données avant d&#39;ajouter <code>not null</code>.</p><hr><h2 id="cascade" tabindex="-1">Cascade <a class="header-anchor" href="#cascade" aria-label="Permalink to &quot;Cascade&quot;">​</a></h2><h3 id="_7-remplacer-la-contrainte-entre-client-et-facture" tabindex="-1">7. Remplacer la contrainte entre <code>client</code> et <code>facture</code> <a class="header-anchor" href="#_7-remplacer-la-contrainte-entre-client-et-facture" aria-label="Permalink to &quot;7. Remplacer la contrainte entre `client` et `facture`&quot;">​</a></h3><p>Repérez d&#39;abord la contrainte existante entre :</p><ul><li><code>facture(client_id)</code></li><li><code>client(client_id)</code></li></ul><p>Ensuite, avec <code>alter table</code> :</p><ol><li>supprimez la contrainte actuelle</li><li>recréez-la avec <code>on delete cascade</code></li></ol><p>But :</p><ul><li>pratiquer le fait qu&#39;on ne modifie pas simplement une cascade sur une FK existante</li><li>observer qu&#39;on remplace la contrainte par une nouvelle version</li></ul><h3 id="_8-remplacer-la-contrainte-entre-facture-et-ligne-facture" tabindex="-1">8. Remplacer la contrainte entre <code>facture</code> et <code>ligne_facture</code> <a class="header-anchor" href="#_8-remplacer-la-contrainte-entre-facture-et-ligne-facture" aria-label="Permalink to &quot;8. Remplacer la contrainte entre `facture` et `ligne_facture`&quot;">​</a></h3><p>Repérez ensuite la contrainte existante entre :</p><ul><li><code>ligne_facture(facture_id)</code></li><li><code>facture(facture_id)</code></li></ul><p>Puis :</p><ol><li>supprimez la contrainte actuelle</li><li>recréez-la avec <code>on delete cascade</code></li></ol><p>Question :</p><ul><li>pourquoi cette relation est-elle une meilleure candidate à <code>on delete cascade</code> ?</li></ul><hr><h2 id="index" tabindex="-1">Index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;Index&quot;">​</a></h2><h3 id="_9-ajouter-des-index-simples" tabindex="-1">9. Ajouter des index simples <a class="header-anchor" href="#_9-ajouter-des-index-simples" aria-label="Permalink to &quot;9. Ajouter des index simples&quot;">​</a></h3><p>Ajoutez les index suivants :</p><ul><li>un index sur <code>employe(ville)</code></li><li>un index sur <code>piste(nom)</code></li></ul><p>Vérifiez ensuite dans DBeaver que ces index existent.</p><p>Question :</p><ul><li>pourquoi un index sur <code>ville</code> ou <code>nom</code> peut-il aider certaines recherches ?</li><li>pourquoi ne pas avoir ajouté un index sur le courriel de l&#39;employé ?</li></ul><h3 id="_10-supprimer-un-index" tabindex="-1">10. Supprimer un index <a class="header-anchor" href="#_10-supprimer-un-index" aria-label="Permalink to &quot;10. Supprimer un index&quot;">​</a></h3><p>Supprimez ensuite l&#39;index sur <code>ville</code>.</p>',68)])])}const h=a(t,[["render",r]]);export{m as __pageData,h as default};
